        """GCD of identical numbers is the number itself."""
        assert gcd(9, 9) == 9

    def test_large_numbers(self):
        assert gcd(1_000_000, 500_000) == 500_000

    def test_large_coprime_numbers(self):
        assert gcd(104_729, 104_723) == 1  # both prime

    def test_fibonacci_consecutive(self):
        """Consecutive Fibonacci numbers are always coprime."""
        assert gcd(144, 89) == 1

